INSERT INTO "parole" (sujet, savant, texte_arabe, texte_francais, phonétique, explication, tag)
SELECT 'Exposition de cas d’apostasie', 'Ibn Jouzayy', '« والذي نفْسُ محمدٍ بيدِهِ ، لا يسمعُ بي أحدٌ من هذه الأمةِ ، لا يهودِيٌّ ، و لا نصرانِيٌّ ، ثُمَّ يموتُ ولم يؤمِنْ بالذي أُرْسِلْتُ به ، إلَّا كان من أصحابِ النارِ «', '', '', 'ce qui a pour sens : « Je jure par Allâh, Celui qui détient mon âme par Sa toute puissance, aucun de cette communauté, ni aucun yahoûdi, ni aucun nasrâni, n’aura entendu parlé de moi puis est mort sans croire en Allâh Celui qui m’a envoyé, sans qu’il ne soit parmi les gens de l’enfer » [rapporté par Mouslim]
– De même, il n’est pas permis de demander à Allâh de faire miséricorde à une personne qui est morte sur la mécréance. Car Allâh nous a clairement indiqué qu’Il ne fera pas miséricorde à ceux qui sont mort mécréant. Il n’est pas permis d’employer à leur sujet des formules comme « rahimahoullâh » , « que Allâh lui fasse miséricorde », « repose en paix » …
– Allâh ta’âlâ dit, dans soûrat An-Niçâ / 48 :', 'al-qawânîn al-fiqhiyyah, apostasie, ibn jouzay, ibn jouzayy'
